import java.util.ArrayList;
import java.util.Arrays;

public class Main {
    public static void main(String[] args) {
        int[] numbers = {10, 25, 3, 47, 8};
        System.out.println("Dizi uzunlugu: " + numbers.length);

        Arrays.sort(numbers);
        System.out.println("Siralanmis dizi: " + Arrays.toString(numbers));

        // ArrayList kullanimi
        ArrayList<String> names = new ArrayList<>();
        names.add("Ali");
        names.add("Veli");
        names.add("Ayse");

        System.out.println("\nIsim listesi:");
        for (String name : names) {
            System.out.println("- " + name);
        }

        names.remove("Veli");
        System.out.println("\nVeli silindikten sonra eleman sayisi: " + names.size());

        // Liste icinde arama
        boolean containsAyse = names.contains("Ayse");
        System.out.println("Ayse listede mi: " + containsAyse);

        // Dizi toplamı
        int total = 0;
        for (int n : numbers) {
            total += n;
        }
        System.out.println("\nToplam: " + total);
    }
}
